:= p_MinP_581037e0, p_MinP_Clear := TRUE, p_FrequencyPenalty := p_FrequencyPenalty_581037e0, p_FrequencyPenalty_Clear := TRUE, p_PresencePenalty := p_PresencePenalty_581037e0, p_PresencePenalty_Clear := TRUE, p_Seed := p_Seed_581037e0, p_Seed_Clear := TRUE, p_StopSequences := p_StopSequences_581037e0, p_IncludeLogProbs := p_IncludeLogProbs_581037e0, p_TopLogProbs := p_TopLogProbs_581037e0, p_TopLogProbs_Clear := TRUE, p_FailoverStrategy := p_FailoverStrategy_581037e0, p_FailoverMaxAttempts := p_FailoverMaxAttempts_581037e0, p_FailoverMaxAttempts_Clear := TRUE, p_FailoverDelaySeconds := p_FailoverDelaySeconds_581037e0, p_FailoverDelaySeconds_Clear := TRUE, p_FailoverModelStrategy := p_FailoverModelStrategy_581037e0, p_FailoverErrorScope := p_FailoverErrorScope_581037e0, p_EffortLevel := p_EffortLevel_581037e0, p_AssistantPrefill := p_AssistantPrefill_581037e0, p_PrefillFallbackMode := p_PrefillFallbackMode_581037e0, p_RequireSpecificModels := p_RequireSpecificModels_581037e0, p_ID := p_ID_581037e0);
