:= p_MinP_1ed48348, p_MinP_Clear := TRUE, p_FrequencyPenalty := p_FrequencyPenalty_1ed48348, p_FrequencyPenalty_Clear := TRUE, p_PresencePenalty := p_PresencePenalty_1ed48348, p_PresencePenalty_Clear := TRUE, p_Seed := p_Seed_1ed48348, p_Seed_Clear := TRUE, p_StopSequences := p_StopSequences_1ed48348, p_IncludeLogProbs := p_IncludeLogProbs_1ed48348, p_TopLogProbs := p_TopLogProbs_1ed48348, p_TopLogProbs_Clear := TRUE, p_FailoverStrategy := p_FailoverStrategy_1ed48348, p_FailoverMaxAttempts := p_FailoverMaxAttempts_1ed48348, p_FailoverDelaySeconds := p_FailoverDelaySeconds_1ed48348, p_FailoverModelStrategy := p_FailoverModelStrategy_1ed48348, p_FailoverErrorScope := p_FailoverErrorScope_1ed48348, p_EffortLevel := p_EffortLevel_1ed48348, p_AssistantPrefill := p_AssistantPrefill_1ed48348, p_PrefillFallbackMode := p_PrefillFallbackMode_1ed48348, p_RequireSpecificModels := p_RequireSpecificModels_1ed48348, p_ID := p_ID_1ed48348);
