  p_Description_ec79d5fa := 'System prompt for the Planning Designer sub-agent that designs agent hierarchies and selects actions.';
  p_TemplateID_ec79d5fa := '7AC7B550-1E59-4945-A9B6-0C100A9E4859';
  p_CategoryID_ec79d5fa := '5A9E8840-2813-4DF6-9FB9-4793FCD36F28';
