  PERFORM __mj."spCreateTemplateContent"(p_ID := p_ID_b88b45c0, p_TemplateID := p_TemplateID_b88b45c0, p_TypeID := p_TypeID_b88b45c0, p_TemplateText := p_TemplateText_b88b45c0, p_Priority := p_Priority_b88b45c0, p_IsActive := p_IsActive_b88b45c0);
